__d(function(e,t,o,a,n,i,r){n.exports=[{name:"Back Escape (Sliding)",japanese_name:null,category:"Back Control",type:"Escape",belt_level:"White",description:"The fundamental back escape involving sliding the back to the floor ('putting shoulders to the mat') to clear the hooks and escape the position.",youtube_url:"https://www.youtube.com/watch?v=W26CrImdW6I",tags:["escape","back","defense","basic","sliding"],id:"back-escape-sliding"},{name:"Bow and Arrow Choke",japanese_name:"Okuri Eri Jime",category:"Back Control",type:"Submission",belt_level:"White",description:"A powerful gi choke using the opponent's collar and their leg/pant to create immense leverage by extending the body like a bow.",youtube_url:"https://www.youtube.com/watch?v=xqNhZVNhxnE",tags:["choke","back","gi","submission","high-percentage"],id:"bow-and-arrow-choke"},{name:"Cross Collar Choke from Back",japanese_name:"Kata Ha Jime",category:"Back Control",type:"Submission",belt_level:"White",description:"A fundamental gi choke where the attacker crosses their arms to grip the opponent's collars deep, applying pressure to the carotids.",youtube_url:"https://www.youtube.com/watch?v=Ow38ejAeB_M",tags:["choke","back","gi","submission","basic"],id:"cross-collar-choke-from-back"},{name:"Prevention (Hand Fighting)",japanese_name:null,category:"Back Control",type:"Defense",belt_level:"White",description:"Early stage defense focusing on fighting the opponent's hands to prevent the seatbelt grip or choke setup before they secure the position.",youtube_url:"https://www.youtube.com/watch?v=GoTtPHjHTuE",tags:["defense","prevention","hand-fighting","back"],id:"prevention-hand-fighting"},{name:"Rear Naked Choke (RNC)",japanese_name:"Hadaka Jime",category:"Back Control",type:"Submission",belt_level:"White",description:"The most iconic submission from the back. One arm wraps around the neck to grab the bicep of the other arm, which goes behind the opponent's head to secure the choke.",youtube_url:"https://www.youtube.com/watch?v=KH6qCjgLXJA",tags:["choke","back","submission","basic","no-gi","gi"],id:"rear-naked-choke-rnc"},{name:"Armbar from Back",japanese_name:"Juji Gatame",category:"Back Control",type:"Submission",belt_level:"Blue",description:"Transitioning from back control to an armbar, typically when the opponent defends the choke by pulling their arm down or extending it.",youtube_url:"https://www.youtube.com/watch?v=4aQQqz-6Baw",tags:["armbar","back","submission","transition","joint-lock"],id:"armbar-from-back"},{name:"Half Nelson Defense",japanese_name:null,category:"Back Control",type:"Defense",belt_level:"Blue",description:"Defending against the half nelson control, which is often used to break posture or turn the defender over to expose the back.",youtube_url:"https://www.youtube.com/watch?v=ULIDpyeqnWs",tags:["defense","half-nelson","wrestling","back"],id:"half-nelson-defense"},{name:"Technical Mount Escape",japanese_name:null,category:"Back Control",type:"Escape",belt_level:"Blue",description:"Escaping the Technical Mount (or S-Mount), a common position attackers transition to from the back. Involves off-balancing or creating space to recover guard.",youtube_url:"https://www.youtube.com/watch?v=5S39-NZsmWk",tags:["escape","mount","technical-mount","defense","transition"],id:"technical-mount-escape"},{name:"Turtle Escape",japanese_name:null,category:"Back Control",type:"Escape",belt_level:"Blue",description:"Recovering guard or standing up from the defensive turtle position, often used to prevent back takes.",youtube_url:"https://www.youtube.com/watch?v=o55M0DMesfE",tags:["escape","turtle","defense","guard-recovery"],id:"turtle-escape"},{name:"Triangle from Back",japanese_name:"Ura Sankaku Jime",category:"Back Control",type:"Submission",belt_level:"Purple",description:"A triangle choke applied from the back mount (often a reverse triangle), trapping the opponent's head and one arm with the legs.",youtube_url:"https://www.youtube.com/watch?v=dZjz1e4jLKM",tags:["triangle","back","submission","reverse-triangle","nogi"],id:"triangle-from-back"},{name:"Clock Choke",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Blue",description:"The Clock Choke is a fundamental technique in Brazilian Jiu-Jitsu. It involves using your body positioning to apply pressure to your opponent's neck, causing them to submit. This technique can be used from various positions, including the north-south position and the mount position.",youtube_url:"",tags:["Choke","BJJ"],id:"clock-choke"},{name:"Loop Choke (from guard)",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Blue",description:"The Loop Choke from Guard is a fundamental technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from the guard position, where you are on your back, with your legs wrapped around your opponent's body.",youtube_url:"",tags:["Choke","Guard","BJJ"],id:"loop-choke-from-guard"},{name:"North-South Choke",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Blue",description:"The North-South Choke is a fundamental technique in Brazilian Jiu-Jitsu. It involves using your body positioning to apply pressure to your opponent's neck, causing them to submit. This technique can be used from the north-south position, where you are on top of your opponent, with your knees pinning their shoulders to the ground.",youtube_url:"https://www.youtube.com/watch?v=KdnEwvlWWm0",tags:["Choke","North-South","BJJ"],id:"northsouth-choke"},{name:"Baseball Bat Choke",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Purple",description:"The Baseball Bat Choke is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from various positions, including the north-south position and the mount position.",youtube_url:"https://www.youtube.com/playlist?list=PLSeGb9wgGmGi80AL_Uu5N-1SXFiGPXxg1",tags:["Choke","BJJ"],id:"baseball-bat-choke"},{name:"Bread Cutter (clock choke variant)",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Purple",description:"The Bread Cutter, also known as the clock choke variant, is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from various positions, including the north-south position and the mount position.",youtube_url:"",tags:["Choke","BJJ"],id:"bread-cutter-clock-choke-variant"},{name:"D'Arce from Mount",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Purple",description:"The D'Arce Choke from Mount is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from the mount position, where you are sitting on top of your opponent, with your knees pinning their hips to the ground.",youtube_url:"",tags:["Choke","Mount","BJJ"],id:"darce-from-mount"},{name:"Loop Choke (from turtle)",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Purple",description:"The Loop Choke from Turtle is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from the turtle position, where you are on your hands and knees, with your opponent controlling your back.",youtube_url:"",tags:["Choke","Turtle","BJJ"],id:"loop-choke-from-turtle"},{name:"Canto Choke",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Brown",description:"The Canto Choke is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from various positions, including the north-south position and the mount position.",youtube_url:"",tags:["Choke","BJJ"],id:"canto-choke"},{name:"Ezekiel from Mount",japanese_name:"",category:"Choke",type:"Submission",belt_level:"Brown",description:"The Ezekiel Choke from Mount is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to apply pressure to your opponent's neck, causing them to submit. This technique can be used from the mount position, where you are sitting on top of your opponent, with your knees pinning their hips to the ground.",youtube_url:"",tags:["Choke","Mount","BJJ"],id:"ezekiel-from-mount"},{name:"Gift Wrap (harness) control",japanese_name:"",category:"Control",type:"Submission",belt_level:"Brown",description:"The Gift Wrap, also known as the harness control, is an advanced technique in Brazilian Jiu-Jitsu. It involves using your body positioning and arm placement to control your opponent's body, setting up for various submissions. This technique can be used from various positions, including the north-south position and the mount position.",youtube_url:"",tags:["Control","BJJ"],id:"gift-wrap-harness-control"},{name:"Armbar from Closed Guard",japanese_name:"Juji Gatame",category:"Guard",type:"Submission",belt_level:"White",description:"A classic joint lock attacking the elbow. The guard player isolates an arm, climbs their legs high, and hyperextends the elbow joint.",youtube_url:"",tags:["guard","submission","gi","white","closed guard","armbar"],id:"armbar-from-closed-guard"},{name:"Butterfly Sweep",japanese_name:"Sumi Gaeshi",category:"Guard",type:"Sweep",belt_level:"White",description:"The classic butterfly hook sweep. The player uses an underhook and a hook lift to flip the opponent to the side.",youtube_url:"",tags:["guard","sweep","gi","white","butterfly guard"],id:"butterfly-sweep"},{name:"Cross Collar Choke",japanese_name:"Nami Juji Jime / Gyaku Juji Jime",category:"Guard",type:"Submission",belt_level:"White",description:"A fundamental choke from closed guard using the opponent's lapels. The hands are crossed deep into the collar to apply pressure to the carotid arteries.",youtube_url:"",tags:["guard","submission","gi","white","closed guard","choke"],id:"cross-collar-choke"},{name:"Double Ankle Sweep",japanese_name:"Kibisu Gaeshi",category:"Guard",type:"Sweep",belt_level:"White",description:"A reactive sweep used when the opponent stands up in closed guard. The guard player drops their hips, grabs both ankles, and drives their hips forward to topple the opponent backward.",youtube_url:"",tags:["guard","sweep","gi","white","closed guard","double ankle"],id:"double-ankle-sweep"},{name:"Guillotine Choke from Closed Guard",japanese_name:"Mae Hadaka Jime",category:"Guard",type:"Submission",belt_level:"White",description:"A choke applied from the front where the opponent's head is trapped under the armpit. Often used when the opponent postures down or drives forward.",youtube_url:"",tags:["guard","submission","gi","white","closed guard","guillotine"],id:"guillotine-choke-from-closed-guard"},{name:"Hip Bump Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"White",description:"A high-percentage sweep from closed guard used when the opponent postures up. The guard player sits up, isolates an arm, and drives their hips into the opponent to knock them over.",youtube_url:"",tags:["guard","sweep","gi","white","closed guard","hip bump"],id:"hip-bump-sweep"},{name:"Kimura from Closed Guard",japanese_name:"Ude Garami",category:"Guard",type:"Submission",belt_level:"White",description:"A shoulder lock applied by gripping the opponent's wrist and your own wrist (figure-four grip) and rotating the arm behind their back.",youtube_url:"",tags:["guard","submission","gi","white","closed guard","kimura"],id:"kimura-from-closed-guard"},{name:"Scissor Sweep",japanese_name:"Hasami Gaeshi",category:"Guard",type:"Sweep",belt_level:"White",description:"A fundamental sweep using a knee shield across the opponent's chest and a scissoring leg motion to chop their base out from underneath them.",youtube_url:"",tags:["guard","sweep","gi","white","closed guard","scissor sweep"],id:"scissor-sweep"},{name:"Straight Ankle Lock",japanese_name:"Ashikubi Gatame",category:"Guard",type:"Submission",belt_level:"White",description:"A leg lock attacking the foot/ankle. Typically set up from Ashi Garami (Single Leg X) position.",youtube_url:"",tags:["guard","submission","gi","white","open guard","leg lock","ankle lock"],id:"straight-ankle-lock"},{name:"Triangle Choke from Closed Guard",japanese_name:"Sankaku Jime",category:"Guard",type:"Submission",belt_level:"White",description:"A stranglehold using the legs to encircle the opponent's neck and one arm. Pressure is applied by squeezing the thighs and pulling the head.",youtube_url:"",tags:["guard","submission","gi","white","closed guard","triangle"],id:"triangle-choke-from-closed-guard"},{name:"Armbar from Spider Guard",japanese_name:"Juji Gatame",category:"Guard",type:"Submission",belt_level:"Blue",description:"An armbar setup using the spider guard (feet on biceps) to stretch the opponent out and isolate an arm for the finish.",youtube_url:"",tags:["guard","submission","gi","blue","open guard","spider guard","armbar"],id:"armbar-from-spider-guard"},{name:"Balloon Sweep",japanese_name:"Tomoe Nage",category:"Guard",type:"Sweep",belt_level:"Blue",description:"A sacrifice throw used from open guard or collar/sleeve. The guard player places a foot on the opponent's hip and rolls back to launch them overhead.",youtube_url:"",tags:["guard","sweep","gi","blue","open guard","tomoe nage"],id:"balloon-sweep"},{name:"Collar Sleeve Tripod Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"A classic open guard sweep where the attacker controls a sleeve and collar, places one foot on the opponent's hip and hooks the other behind their knee/ankle to trip them.",youtube_url:"",tags:["guard","sweep","gi","blue","open guard","collar sleeve","tripod sweep"],id:"collar-sleeve-tripod-sweep"},{name:"De La Riva Sit-up Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"From De La Riva guard, the player sits up to grab the opponent's lapel or leg (single leg), driving into them to force a takedown or sweep.",youtube_url:"",tags:["guard","sweep","gi","blue","open guard","de la riva"],id:"de-la-riva-situp-sweep"},{name:"Deep Half to Guard",japanese_name:null,category:"Guard",type:"Recovery",belt_level:"Blue",description:"Technique for transitioning from deep half to guard in BJJ",youtube_url:"https://www.youtube.com/watch?v=dQw4w9WgXcQ",tags:["bjj","guard","deep half"],id:"deep-half-to-guard"},{name:"Flower Sweep / Pendulum Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"An elevator-style sweep where the guard player underhooks the leg and uses a pendulum momentum with their legs to flip the opponent.",youtube_url:"",tags:["guard","sweep","gi","blue","closed guard","flower sweep"],id:"flower-sweep--pendulum-sweep"},{name:"Frame and Pummel",japanese_name:null,category:"Guard",type:"Retention",belt_level:"Blue",description:"Frame and pummel technique for retaining guard in BJJ",youtube_url:"https://www.youtube.com/watch?v=dQw4w9WgXcQ",tags:["bjj","guard","frame","pummel"],id:"frame-and-pummel"},{name:"Granby Roll",japanese_name:null,category:"Guard",type:"Retention",belt_level:"Blue",description:"Granby roll technique for retaining guard in BJJ",youtube_url:"https://www.youtube.com/watch?v=KjncAL40Q6g",tags:["bjj","guard","granby roll"],id:"granby-roll"},{name:"Guard Recovery from Half Guard",japanese_name:null,category:"Guard",type:"Recovery",belt_level:"Blue",description:"Technique for recovering guard from half guard in BJJ",youtube_url:"https://www.youtube.com/watch?v=KjncAL40Q6g",tags:["bjj","guard","recovery","half guard"],id:"guard-recovery-from-half-guard"},{name:"Half Guard Underhook Sweep (Coyote/Old School)",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"A fundamental half guard sweep relying on a strong underhook. The player comes up to their knees, trapping the opponent's leg (dogfight position), and drives for the reversal.",youtube_url:"",tags:["guard","sweep","gi","blue","half guard","underhook","dogfight"],id:"half-guard-underhook-sweep-coyoteold-school"},{name:"Hip Heist / Shrimp",japanese_name:null,category:"Guard",type:"Retention",belt_level:"Blue",description:"Hip heist shrimp technique for escaping bad positions in BJJ",youtube_url:"https://www.youtube.com/watch?v=jNQo4Nz5rnA",tags:["bjj","guard","hip heist","shrimp"],id:"hip-heist--shrimp"},{name:"John Wayne Sweep / Knee Lever",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"A deception sweep from half guard. When the opponent pressures into the shield, the bottom player collapses their knees to the side to off-balance and roll the opponent.",youtube_url:"",tags:["guard","sweep","gi","blue","half guard","knee lever"],id:"john-wayne-sweep--knee-lever"},{name:"Knee Shield (Z-Guard)",japanese_name:null,category:"Guard",type:"Retention",belt_level:"Blue",description:"Knee shield z-guard technique for guarding in BJJ",youtube_url:"https://www.youtube.com/watch?v=-AdaVO7ywzs",tags:["bjj","guard","knee shield","z-guard"],id:"knee-shield-zguard"},{name:"Lasso Guard Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"Using the lasso hook (leg through the arm) to control the opponent's posture and off-balance them for a sweep, often rotating underneath.",youtube_url:"",tags:["guard","sweep","gi","blue","open guard","lasso guard"],id:"lasso-guard-sweep"},{name:"Loop Choke from Closed Guard",japanese_name:null,category:"Guard",type:"Submission",belt_level:"Blue",description:"A lapel choke where the guard player feeds the opponent's collar under their chin and loops their arm around the head to finish.",youtube_url:"",tags:["guard","submission","gi","blue","closed guard","loop choke"],id:"loop-choke-from-closed-guard"},{name:"Omoplata from Closed Guard",japanese_name:"Ashi Sankaku Garami",category:"Guard",type:"Submission",belt_level:"Blue",description:"A shoulder lock using the legs. The guard player isolates an arm and rotates their body to place the leg over the opponent's shoulder, forcing it backward.",youtube_url:"",tags:["guard","submission","gi","blue","closed guard","omoplata"],id:"omoplata-from-closed-guard"},{name:"Quarter Guard Recomposition",japanese_name:null,category:"Guard",type:"Recovery",belt_level:"Blue",description:"Technique for recomposing guard from quarter guard in BJJ",youtube_url:"https://www.youtube.com/watch?v=KjncAL40Q6g",tags:["bjj","guard","quarter guard"],id:"quarter-guard-recomposition"},{name:"Spider Guard Kite Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Blue",description:"A powerful sweep from spider guard involving loading the opponent onto one leg (the kite) and steering them over with the other.",youtube_url:"",tags:["guard","sweep","gi","blue","open guard","spider guard"],id:"spider-guard-kite-sweep"},{name:"Technical Stand-Up",japanese_name:null,category:"Guard",type:"Recovery",belt_level:"Blue",description:"Technical stand-up technique for recovering guard in BJJ",youtube_url:"https://www.youtube.com/watch?v=yC_sSqO4Vx0",tags:["bjj","guard","technical stand-up"],id:"technical-standup"},{name:"Triangle Choke from Collar Sleeve Guard",japanese_name:"Sankaku Jime",category:"Guard",type:"Submission",belt_level:"Blue",description:"Setting up the triangle choke from an open guard using collar and sleeve grips. Creates strong posture control before shooting the legs.",youtube_url:"",tags:["guard","submission","gi","blue","open guard","triangle","collar sleeve"],id:"triangle-choke-from-collar-sleeve-guard"},{name:"Turtle to Guard Recovery",japanese_name:null,category:"Guard",type:"Recovery",belt_level:"Blue",description:"Technique for recovering guard from turtle position in BJJ",youtube_url:"https://www.youtube.com/watch?v=jNQo4Nz5rnA",tags:["bjj","guard","turtle"],id:"turtle-to-guard-recovery"},{name:"Underhook Guard Retention",japanese_name:null,category:"Guard",type:"Retention",belt_level:"Blue",description:"Underhook guard retention technique for BJJ",youtube_url:"https://www.youtube.com/watch?v=dQw4w9WgXcQ",tags:["bjj","guard","underhook"],id:"underhook-guard-retention"},{name:"Deep Half Waiter Sweep",japanese_name:null,category:"Guard",type:"Sweep",belt_level:"Purple",description:"From deep half guard, the player underhooks the leg and uses a pendulum motion with their legs to unbalance the opponent backward.",youtube_url:"",tags:["guard","sweep","gi","purple","half guard","deep half"],id:"deep-half-waiter-sweep"},{name:"Entry to 50/50 from Butterfly Guard",japanese_name:null,category:"Leg Entanglements",type:"Entry",belt_level:"Blue",description:"From butterfly guard, engage in an underhook battle and pummel to secure single underhook. Shoot your leg through to entangle opponent's leg while maintaining upper body control, transitioning into the 50/50 position.",youtube_url:"https://www.youtube.com/watch?v=GXVq-4v1RdA",tags:["leg-entanglements","50-50","entry","butterfly-guard","transition"],id:"entry-to-5050-from-butterfly-guard"},{name:"Straight Ankle Lock from Ashi Garami",japanese_name:"Ashi Hishigi",category:"Leg Entanglements",type:"Submission",belt_level:"Blue",description:"From Ashi Garami (single leg X), control opponent's leg by gripping their heel and applying pressure to the ankle joint by bridging hips forward while keeping their foot trapped between your armpit and hip.",youtube_url:"https://www.youtube.com/watch?v=J3V3h1X9w1s",tags:["leg-entanglements","ashi-garami","ankle-lock","submission","straight-foot-lock"],id:"straight-ankle-lock-from-ashi-garami"},{name:"Kneebar from 50/50",japanese_name:"Hiza Hishigi",category:"Leg Entanglements",type:"Submission",belt_level:"Purple",description:"From 50/50, identify when opponent exposes their leg by straightening. Control their foot under your armpit, clear your entangled leg, and fall back into kneebar position while maintaining hip extension pressure.",youtube_url:"https://www.youtube.com/watch?v=jrH1CtM8o1Q",tags:["leg-entanglements","50-50","kneebar","submission"],id:"kneebar-from-5050"},{name:"Kneebar from Ashi Garami",japanese_name:"Hiza Hishigi",category:"Leg Entanglements",type:"Submission",belt_level:"Purple",description:"From Ashi Garami, fall back into a kneebar position by controlling the opponent's leg and straightening it fully. Secure their heel under your armpit and extend your hips to apply pressure to the knee joint.",youtube_url:"https://www.youtube.com/watch?v=nj6hJo8D7hk",tags:["leg-entanglements","ashi-garami","kneebar","submission","leg-lock"],id:"kneebar-from-ashi-garami"},{name:"Saddle Entry from De La Riva",japanese_name:null,category:"Leg Entanglements",type:"Entry",belt_level:"Purple",description:"From De La Riva guard, extend your hook leg to push opponent's leg across your body. Thread your opposite leg underneath to trap their leg between yours, then rotate to saddle position while maintaining upper body grips.",youtube_url:"https://www.youtube.com/watch?v=QZVj5W3Bq1Y",tags:["leg-entanglements","saddle","entry","de-la-riva","transition"],id:"saddle-entry-from-de-la-riva"},{name:"Toe Hold from Ashi Garami",japanese_name:"Tsume Tori",category:"Leg Entanglements",type:"Submission",belt_level:"Purple",description:"From Ashi Garami, trap the opponent's foot and grip their toes/ball of foot. Apply rotational pressure by turning the foot toward the outside of the hip while controlling the leg, creating a twisting submission on the ankle and knee.",youtube_url:"https://www.youtube.com/watch?v=cVHy8EWg1K8",tags:["leg-entanglements","ashi-garami","toe-hold","submission","rotational-lock"],id:"toe-hold-from-ashi-garami"},{name:"Heel Hook from 50/50 Position",japanese_name:"Sankaku Ashi",category:"Leg Entanglements",type:"Submission",belt_level:"Brown",description:"From the 50/50 entanglement where both legs are intertwined, secure underhook access to opponent's heel. Fall to the opposite side of the trapped leg and apply rotational heel hook pressure using both hands for control.",youtube_url:"https://www.youtube.com/watch?v=EDcjMAK9Oj0",tags:["leg-entanglements","50-50","heel-hook","submission","sankaku-ashi"],id:"heel-hook-from-5050-position"},{name:"Heel Hook from Ashi Garami",japanese_name:"Ashi Garami",category:"Leg Entanglements",type:"Submission",belt_level:"Brown",description:"From Ashi Garami position, secure a heel hook grip by controlling the opponent's heel with your wrist as a fulcrum. Apply rotational pressure to the knee by turning the heel toward the opponent's hip while controlling their leg.",youtube_url:"https://www.youtube.com/watch?v=GRwufC8qTEE",tags:["leg-entanglements","ashi-garami","heel-hook","submission","knee-torque"],id:"heel-hook-from-ashi-garami"},{name:"Heel Hook from Saddle (Honey Hole)",japanese_name:"Saddle Position",category:"Leg Entanglements",type:"Submission",belt_level:"Brown",description:"From Saddle position (one leg threaded through opponent's legs, other leg controlling), underhook the heel and fall to the controlled side. Apply heel hook torque by rotating heel toward their hip while maintaining saddle control with your free leg.",youtube_url:"https://www.youtube.com/watch?v=-9iOmDkjR1s",tags:["leg-entanglements","saddle","honey-hole","heel-hook","submission"],id:"heel-hook-from-saddle-honey-hole"},{name:"Inside Heel Hook from Saddle",japanese_name:null,category:"Leg Entanglements",type:"Submission",belt_level:"Brown",description:"From saddle position, attack the inside heel hook by controlling the trapped leg's heel with a reverse grip. Fall to the controlled side and apply inward rotational pressure, torque against normal rotation while controlling their hip with your free leg.",youtube_url:"https://www.youtube.com/watch?v=WdMDGf8hC2U",tags:["leg-entanglements","saddle","heel-hook","inside-heel-hook","submission"],id:"inside-heel-hook-from-saddle"},{name:"Americana",japanese_name:"Ude Garami",category:"Mount",type:"Submission",belt_level:"White",description:"A shoulder lock applied from the mount. Isolate the opponent's arm on the mat, bent at a 90-degree angle. Thread your opposite arm under their tricep and grab your own wrist (figure-four grip). Drag the opponent's elbow down towards their hip while keeping their wrist pinned, then lift the elbow to apply torque to the shoulder.",youtube_url:"https://www.youtube.com/watch?v=GSO8-YYOm18",tags:["mount","submission","gi","joint lock","white belt"],id:"americana"},{name:"Armbar from Mount",japanese_name:"Juji Gatame",category:"Mount",type:"Submission",belt_level:"White",description:"One of the most classic submissions in BJJ. Isolate an arm by driving your weight forward and securing a high mount or S-mount. Step your leg over the opponent's head while maintaining tight control of the arm. Sit back, squeezing your knees together, and hyperextend the elbow joint. Roger Gracie emphasizes using a specific grip to control the arm before the transition.",youtube_url:"https://www.youtube.com/watch?v=b_1U3br_mOM",tags:["mount","submission","gi","armbar","white belt"],id:"armbar-from-mount"},{name:"Bridge and Roll (Upa)",japanese_name:null,category:"Mount",type:"Escape",belt_level:"White",description:"The fundamental mount escape. Trap the opponent's arm and foot on the same side to prevent them from posting. Bridge your hips explosively straight up, then roll over your shoulder towards the trapped side to reverse the position and end up in their guard.",youtube_url:"https://www.youtube.com/watch?v=01Fe3N1vZMY",tags:["mount","escape","gi","white belt"],id:"bridge-and-roll-upa"},{name:"Cross Collar Choke from Mount",japanese_name:"Juji Jime",category:"Mount",type:"Submission",belt_level:"White",description:"Roger Gracie's signature submission from the mount. Establish a deep cross collar grip with one hand, opening the collar with the other. The second hand goes under the first to grip the opposite collar (palm up) or the shoulder (palm down). Bring your head down to the mat on the side of the top arm and expand your chest to apply pressure. A fundamental and high-percentage choke.",youtube_url:"https://www.youtube.com/watch?v=8wLWTw8G0c0",tags:["mount","submission","gi","choke","white belt"],id:"cross-collar-choke-from-mount"},{name:"Elbow Escape (Shrimp)",japanese_name:"Ebi",category:"Mount",type:"Escape",belt_level:"White",description:"Also known as the Elbow-Knee escape. Turn to your side and use your elbow and forearm to create a frame against the opponent's hip/knee. Shrimp your hips out to create space, then insert your bottom knee between you and the opponent. Recover half guard or full guard.",youtube_url:"https://www.youtube.com/watch?v=Wxr5RqtYZ_c",tags:["mount","escape","gi","white belt"],id:"elbow-escape-shrimp"},{name:"Ezekiel Choke",japanese_name:"Sode Guruma Jime",category:"Mount",type:"Submission",belt_level:"White",description:"A choke that relies on using your own gi sleeve rather than the opponent's collar. From mount, one arm goes behind the opponent's head while the other hand grabs the inside of that arm's sleeve. The forearm is then brought across the opponent's throat. This choke is effective because it can be applied even if the opponent defends their neck tight to their body.",youtube_url:"https://www.youtube.com/watch?v=KVnengZD1XA",tags:["mount","submission","gi","choke","white belt"],id:"ezekiel-choke"},{name:"Baseball Bat Choke",japanese_name:null,category:"Mount",type:"Submission",belt_level:"Blue",description:"A deceptive choke where you grip the opponent's collar with both hands like holding a baseball bat (one palm up, one palm down). From mount, this often requires a transition or baiting a guard recovery. The finish typically involves spinning or dismounting to North-South to tighten the collar around the neck.",youtube_url:"https://www.youtube.com/watch?v=oi3Uh08cqsw",tags:["mount","submission","gi","choke","blue belt"],id:"baseball-bat-choke"},{name:"Heel Drag Escape",japanese_name:null,category:"Mount",type:"Escape",belt_level:"Blue",description:"An effective escape when the opponent has their legs flat or grapevined. Use your heel to hook over the opponent's ankle/shin and drag it over your other leg, trapping it to enter half guard. Often combined with the elbow escape mechanics.",youtube_url:"https://www.youtube.com/watch?v=00CjhoOsmuI",tags:["mount","escape","gi","blue belt"],id:"heel-drag-escape"},{name:"Arm Triangle (No-Gi)",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Blue",description:"The arm triangle choke is applied from side control or mount. Trap your opponent's head and arm, then use your body to squeeze their neck between your arm and shoulder. The key is to cut off blood flow to the carotid arteries by maintaining tight pressure and controlling their posture.",youtube_url:"https://www.youtube.com/watch?v=XMN6eFY0u-g",tags:["no-gi","submission","blue","arm triangle","choke"],id:"arm-triangle-nogi"},{name:"Guillotine Choke",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Blue",description:"The guillotine choke is applied from the front headlock position. Secure a tight grip around the opponent's neck with your arm, using your body to squeeze and cut off their airway. The high elbow variation, as taught by John Danaher, increases the choke's effectiveness by focusing pressure on the carotid arteries.",youtube_url:"https://www.youtube.com/watch?v=XCiRr7TW2bk",tags:["no-gi","submission","blue","guillotine","choke"],id:"guillotine-choke"},{name:"Kimura (No-Gi)",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Blue",description:"The Kimura is a shoulder lock applied from side control, mount, or guard. Grip your opponent's wrist with one hand and their elbow with the other, then rotate their arm behind their back to hyperextend the shoulder joint. This submission is highly effective in both gi and no-gi grappling due to its versatility.",youtube_url:"https://www.youtube.com/watch?v=g4c5RG4KYlo",tags:["no-gi","submission","blue","kimura","shoulder lock"],id:"kimura-nogi"},{name:"Anaconda Choke",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Purple",description:"The Anaconda choke is a powerful front headlock submission. Trap your opponent's head and arm, then thread your arm underneath their neck and lock your hands. Roll over your shoulder to apply pressure, cutting off blood flow to the carotid arteries. This choke is highly effective in both gi and no-gi grappling.",youtube_url:"https://www.youtube.com/watch?v=3D6X6xE1J4M",tags:["no-gi","submission","purple","anaconda","choke"],id:"anaconda-choke"},{name:"Darce Choke (Brabo)",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Purple",description:"The Darce choke is an arm-in choke applied from the front headlock position. Grip your opponent's neck with your arm, threading your other arm underneath their armpit and locking your hands. Squeeze your elbows together and drive your shoulder into their neck to cut off blood flow. Lachlan Giles emphasizes the importance of grip details and head control for a successful finish.",youtube_url:"https://www.youtube.com/watch?v=sSVcHmYvtkA",tags:["no-gi","submission","purple","darce","choke"],id:"darce-choke-brabo"},{name:"Kneebar (No-Gi)",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Purple",description:"The kneebar is a leg lock that hyperextends the knee joint by applying pressure to the leg while controlling the opponent's hip. This submission is highly effective in no-gi grappling and can be applied from a variety of positions, including guard and leg entanglements. Proper control and technique are essential to avoid injury.",youtube_url:"https://www.youtube.com/watch?v=5XQ3QJZJZ1E",tags:["no-gi","submission","purple","kneebar","leg lock"],id:"kneebar-nogi"},{name:"Calf Slicer",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Brown",description:"The calf slicer is a compression lock that targets the calf muscle by applying pressure to the back of the leg. This submission is applied by trapping the opponent's leg between your arms and legs, then squeezing to compress the calf muscle against your shin. The calf slicer is highly effective in no-gi grappling and can cause significant discomfort.",youtube_url:"https://www.youtube.com/watch?v=3D6X6xE1J4M",tags:["no-gi","submission","brown","calf slicer","leg lock"],id:"calf-slicer"},{name:"Heel Hook (No-Gi)",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Brown",description:"The heel hook is a leg lock that targets the knee joint by applying rotational pressure to the heel. This submission is highly effective in no-gi grappling and requires precise control to avoid injury. It is essential to understand the mechanics of the heel hook and practice it safely to avoid damaging your training partner's knee.",youtube_url:"https://www.youtube.com/watch?v=hNTsYUShvLU",tags:["no-gi","submission","brown","heel hook","leg lock"],id:"heel-hook-nogi"},{name:"Japanese Necktie",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Brown",description:"The Japanese Necktie is a versatile and sneaky choke applied from the front headlock or turtle position. Trap your opponent's head and arm, then thread your leg over their shoulder to secure the choke. Use your arms to control their posture and apply pressure to their neck, forcing them to tap.",youtube_url:"https://www.youtube.com/watch?v=5XQ3QJZJZ1E",tags:["no-gi","submission","brown","japanese necktie","choke"],id:"japanese-necktie"},{name:"Twister (Spinal Lock)",japanese_name:null,category:"No-Gi",type:"Submission",belt_level:"Brown",description:"The Twister is a spinal lock applied from the back control position. Trap your opponent's head and arm, then use your legs to control their body while applying rotational pressure to their spine. This submission is highly effective in no-gi grappling and requires precise control to avoid injury.",youtube_url:"https://www.youtube.com/watch?v=V3nDmb66Xpc",tags:["no-gi","submission","brown","twister","spinal lock"],id:"twister-spinal-lock"},{name:"Americana from Side Control",japanese_name:"Ude Garami",category:"Side Control",type:"Submission",belt_level:"White",description:"Isolate the opponent's far arm and pin their wrist to the mat with your hand (palm up). Thread your other arm under their tricep and grab your own wrist to form a figure-four lock. Drag their elbow down towards their hip to take out the slack, then lift their elbow while keeping their wrist pinned to the mat to apply shoulder pressure.",youtube_url:"https://www.youtube.com/watch?v=4oC0urX4y3k",tags:["submission","arm lock","basic","shoulder lock"],id:"americana-from-side-control"},{name:"Bridge and Shrimp Escape",japanese_name:"Upa & Ebi",category:"Side Control",type:"Escape",belt_level:"White",description:"Plant your feet close to your hips. Bridge explosively into the opponent to create space. Immediately shrimp (hip escape) your hips away, bringing your bottom knee between you and the opponent to re-establish a frame or recover guard.",youtube_url:"https://www.youtube.com/watch?v=ZzOqifoQ_TM",tags:["escape","defense","fundamental","guard recovery"],id:"bridge-and-shrimp-escape"},{name:"Kimura from Side Control",japanese_name:"Ude Garami (Reverse)",category:"Side Control",type:"Submission",belt_level:"White",description:"Attack the far arm. Pin their wrist or grab it with your hand. Thread your other arm over their tricep and under their arm to grab your own wrist (figure-four grip). Keep their elbow tight to your chest, step over their head with your leg if needed to prevent them from sitting up, and rotate their arm behind their back.",youtube_url:"https://www.youtube.com/watch?v=apOPhMHTt0Q",tags:["submission","arm lock","shoulder lock","control"],id:"kimura-from-side-control"},{name:"Knee Elbow Escape (Reguarding)",japanese_name:null,category:"Side Control",type:"Escape",belt_level:"White",description:"Frame against the opponent's neck and hip to prevent them from settling. Bridge to create a small gap, then quickly bring your bottom knee inside to connect with your bottom elbow. Use this 'knee-elbow shield' to push the opponent away and recover full guard.",youtube_url:"https://www.youtube.com/watch?v=7FdN70-BUfU",tags:["escape","defense","fundamental","guard retention"],id:"knee-elbow-escape-reguarding"},{name:"Arm Triangle (Kata Gatame)",japanese_name:"Kata Gatame",category:"Side Control",type:"Submission",belt_level:"Blue",description:"Isolate the opponent's arm across their own neck. Clasp your hands together (gable grip) or grab your own bicep behind their neck. Dismount to the side opposite the trapped arm, sprawl your hips, and drive your shoulder into their neck while squeezing to cut off blood flow.",youtube_url:"https://www.youtube.com/watch?v=8An-33URyYk",tags:["submission","choke","strangle","pressure"],id:"arm-triangle-kata-gatame"},{name:"Baseball Bat Choke",japanese_name:null,category:"Side Control",type:"Submission",belt_level:"Blue",description:"Secure a grip on the opponent's collar with both hands (thumbs in, like holding a baseball bat). Spin your body towards North-South or walk around their head. The crossing of your arms creates a powerful choke as you rotate.",youtube_url:"https://www.youtube.com/watch?v=8L0GzGKbZFQ",tags:["submission","choke","gi","surprise"],id:"baseball-bat-choke"},{name:"Paper Cutter Choke",japanese_name:"Bread Cutter Choke",category:"Side Control",type:"Submission",belt_level:"Blue",description:"From side control, isolate the near arm. Grip the back of the opponent's collar with your far hand (thumb inside). Drop your elbow across their neck. With your other hand, control their far arm or hip. Rotate your body towards their head (North-South direction) to apply pressure with your forearm against their throat.",youtube_url:"https://www.youtube.com/watch?v=ez-CO8kUpHA",tags:["submission","choke","gi","lapel choke"],id:"paper-cutter-choke"},{name:"Spinning Armbar",japanese_name:"Juji Gatame (Spinning)",category:"Side Control",type:"Submission",belt_level:"Blue",description:"From side control (often Knee-on-Belly or modified side), step your leg over the opponent's head. Pivot on your other knee and spin 180 degrees to the other side, collecting their far arm. Sit back, pinch your knees, and extend your hips to finish the armbar.",youtube_url:"https://www.youtube.com/watch?v=ct_TpL2u00k",tags:["submission","arm lock","dynamic","transition"],id:"spinning-armbar"},{name:"Underhook Escape",japanese_name:null,category:"Side Control",type:"Escape",belt_level:"Blue",description:"Swim your near arm under the opponent's armpit to get a deep underhook. Bridge to create space and bump them forward. Use the underhook to lift yourself up to your knees (dogfight position) or slide out the back door to take the back.",youtube_url:"https://www.youtube.com/watch?v=nhkD8sIqQFc",tags:["escape","defense","wrestling","transition"],id:"underhook-escape"},{name:"Ghost Escape",japanese_name:null,category:"Side Control",type:"Escape",belt_level:"Purple",description:"When the opponent has a tight crossface or underhook, frame and dive your head *under* their arm or body. Circle your body towards their legs and out the other side (North-South) to escape completely, often ending up in a dominant position.",youtube_url:"https://www.youtube.com/watch?v=6ZKFobk8vOQ",tags:["escape","defense","advanced","mobility"],id:"ghost-escape"},{name:"Neck Crank",japanese_name:"Kubi Hishigi (Generic)",category:"Side Control",type:"Submission",belt_level:"Purple",description:"Control the opponent's head, often using a 'Can Opener' grip or by wrapping the head. Apply pressure to force the chin to the chest or twist the neck. Caution: This technique can be dangerous and is illegal in some competitions.",youtube_url:"https://www.youtube.com/watch?v=E6aYmdNpNrk",tags:["submission","crank","spine","dangerous"],id:"neck-crank"},{name:"Ankle Pick",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"White",description:"A low-risk takedown using wrist control and collar tie to break posture, then quickly stepping in to grab the ankle while pulling head down and forward, off-balancing opponent onto their back.",youtube_url:"https://www.youtube.com/watch?v=CTxdnhV-u60",tags:["wrestling","ankle-pick","low-risk","head-pull","wrist-control"],id:"ankle-pick"},{name:"Double Leg",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"White",description:"The fundamental wrestling takedown. Level change, step forward, drive both arms around opponent's legs while keeping head to the side, then finish by running them down or lifting and slamming to mat.",youtube_url:"https://www.youtube.com/watch?v=5lQxA5LW9VQ",tags:["wrestling","double-leg","fundamental","shot","white-belt"],id:"double-leg"},{name:"Ko Soto Gari",japanese_name:"\u5c0f\u5916\u5208 (Minor Outer Reap)",category:"Standing",type:"Takedown",belt_level:"White",description:"The minor outer reap - attack opponent's weighted leg from the outside, reaping just behind the ankle while pulling forward and across. A low-risk throw that works well in BJJ as a disruption and takedown.",youtube_url:"https://www.youtube.com/watch?v=dP2sCszwXmU",tags:["judo","ko-soto-gari","outer-reap","sweeps","ashi-waza","white-belt"],id:"ko-soto-gari"},{name:"Major Hip Throw",japanese_name:"O Goshi",category:"Standing",type:"Throw",belt_level:"White",description:"A fundamental hip throw where the attacker puts their arm around the opponent's waist, loads them onto the back/hip, and lifts them off the ground before rotating to throw.",youtube_url:"https://www.youtube.com/results?search_query=o+goshi+judo",tags:["judo","koshi-waza","hip throw","takedown"],id:"major-hip-throw"},{name:"Major Inner Reap",japanese_name:"Ouchi Gari",category:"Standing",type:"Throw",belt_level:"White",description:"The attacker steps inside the opponent's legs and reaps the opponent's inner leg from the inside out, driving them backward diagonally.",youtube_url:"https://www.youtube.com/results?search_query=ouchi+gari+judo",tags:["judo","ashi-waza","leg throw","takedown"],id:"major-inner-reap"},{name:"Major Outer Reap",japanese_name:"Osoto Gari",category:"Standing",type:"Throw",belt_level:"White",description:"A powerful leg reap where the attacker steps forward to break the opponent's balance backward, then swings their outside leg past the opponent's and reaps back hard against the thigh/calf.",youtube_url:"https://www.youtube.com/results?search_query=osoto+gari+judo",tags:["judo","ashi-waza","leg throw","takedown"],id:"major-outer-reap"},{name:"O Uchi Gari",japanese_name:"\u5927\u5185\u5208 (Major Inner Reap)",category:"Standing",type:"Takedown",belt_level:"White",description:"Classic Judo throw using a sacrifice motion - step deep between opponent's legs, reap their supporting leg from the inside while rotating and pulling them over the reaping leg. Excellent for BJJ with grip fighting adjustments.",youtube_url:"https://www.youtube.com/watch?v=4x6S3V2U04o",tags:["judo","o-uchi-gari","inner-reap","sacrifice","gi-throw","ashi-waza"],id:"o-uchi-gari"},{name:"Single Leg",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"White",description:"Secure one leg with both hands, head inside, and work to finish by running the pipe, switching to a double, or using various finishing mechanics to bring opponent down while maintaining control.",youtube_url:"https://www.youtube.com/watch?v=pN6_yf3Ea54",tags:["wrestling","single-leg","fundamental","propulsion","leg-attack"],id:"single-leg"},{name:"Snap Down",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"White",description:"Use collar ties and wrist control to snap opponent's head down toward the mat while stepping back, creating a reaction. Common setup for front headlock position or guillotines in BJJ.",youtube_url:"https://www.youtube.com/watch?v=sRtbMXbVR0I",tags:["wrestling","snap-down","setup","front-headlock","collar-tie"],id:"snap-down"},{name:"Arm Drag",japanese_name:null,category:"Standing",type:"Position",belt_level:"Blue",description:"The arm drag is a fundamental technique in BJJ that involves grabbing your opponent's arm and pulling it across your body to gain control.",youtube_url:"https://www.youtube.com/watch?v=e_c7G5T_ZR8",tags:["arm drag","BJJ","standing"],id:"arm-drag"},{name:"Blast Double",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"Blue",description:"An explosive, high-impact version of the double leg using a powerful penetration step that covers more distance. Requires timing and commitment - drive through opponent rather than trying to lift them.",youtube_url:"https://www.youtube.com/watch?v=K5p14iDnj0g",tags:["wrestling","blast-double","explosive","power","penetration"],id:"blast-double"},{name:"Duck Under",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"Blue",description:"When opponent commits forward pressure or overextends arms, drop underneath while pulling their arm across your body, circle behind to secure back control or take them down to turtle position.",youtube_url:"https://www.youtube.com/watch?v=ePQTk4X7KdM",tags:["wrestling","duck-under","back-take","angle","counters"],id:"duck-under"},{name:"Floating Technique",japanese_name:"Uki Waza",category:"Standing",type:"Throw",belt_level:"Blue",description:"A sacrifice throw where the attacker drops sideways to break the opponent's balance to the front corner, pulling them over the extended leg.",youtube_url:"https://www.youtube.com/results?search_query=uki+waza+judo",tags:["judo","sutemi-waza","sacrifice throw","takedown"],id:"floating-technique"},{name:"Front Headlock Defense",japanese_name:null,category:"Standing",type:"Defense",belt_level:"Blue",description:"The front headlock defense is a technique used to defend against an opponent's front headlock.",youtube_url:"https://www.youtube.com/watch?v=uRXdQnAEQ_s",tags:["front headlock defense","BJJ","standing"],id:"front-headlock-defense"},{name:"High Crotch",japanese_name:null,category:"Standing",type:"Takedown",belt_level:"Blue",description:"Shoot deep on one leg with arm threading between thighs (high crotch position). From here finish with various options: run the pipe, switch to double, or convert to a single leg finish depending on defense.",youtube_url:"https://www.youtube.com/watch?v=CfuSFjBcEeQ",tags:["wrestling","high-crotch","single-leg","entries","finishes"],id:"high-crotch"},{name:"Koshi Guruma",japanese_name:"\u8170\u8eca (Hip Wheel)",category:"Standing",type:"Takedown",belt_level:"Blue",description:"Enter with deep underhook, load opponent onto your hip with arm around their head. Rotate and wheel them over your hip to the mat while maintaining head control, ideal for BJJ due to landing in side control.",youtube_url:"https://www.youtube.com/watch?v=O99wRgfTuo0",tags:["judo","koshi-guruma","hip-wheel","underhook","landing-position"],id:"koshi-guruma"},{name:"Posting on Shots",japanese_name:null,category:"Standing",type:"Position",belt_level:"Blue",description:"Posting on shots is a technique used to defend against an opponent's takedown attempt.",youtube_url:"https://www.youtube.com/watch?v=uRXdQnAEQ_s",tags:["posting on shots","BJJ","standing"],id:"posting-on-shots"},{name:"Sasae Tsurikomi Ashi",japanese_name:"\u652f\u91e3\u8fbc\u8db3 (Propping Lifting Pull Foot)",category:"Standing",type:"Takedown",belt_level:"Blue",description:"Use sleeve and lapel grips to off-balance opponent forward, then prop/block their advancing ankle with your foot while pulling and lifting - opponent trips over your propping foot and falls forward.",youtube_url:"https://www.youtube.com/watch?v=iT1a2V-Rb8k",tags:["judo","sasae","propping","foot-sweep","ashi-waza","timing"],id:"sasae-tsurikomi-ashi"},{name:"Sprawl Defense",japanese_name:null,category:"Standing",type:"Defense",belt_level:"Blue",description:"The sprawl defense is a technique used to defend against an opponent's takedown attempt.",youtube_url:"https://www.youtube.com/watch?v=CXX4A9Z4nEE",tags:["sprawl defense","BJJ","standing"],id:"sprawl-defense"},{name:"Tai Otoshi",japanese_name:"\u4f53\u843d\u3057 (Body Drop)",category:"Standing",type:"Takedown",belt_level:"Blue",description:"A dynamic hand technique throw using sleeve and lapel grips. Step to the side while blocking opponent's advancing leg with your leg, simultaneously pulling and rotating to throw them directly forward.",youtube_url:"https://www.youtube.com/watch?v=keVRzyucJpQ",tags:["judo","tai-otoshi","body-drop","te-waza","dynamic"],id:"tai-otoshi"},{name:"Whizzer Defense",japanese_name:null,category:"Standing",type:"Defense",belt_level:"Blue",description:"The whizzer defense is a technique used to defend against an opponent's whizzer.",youtube_url:"https://www.youtube.com/watch?v=pTbiUDyFDQE",tags:["whizzer defense","BJJ","standing"],id:"whizzer-defense"},{name:"Whizzer/Collar Tie",japanese_name:null,category:"Standing",type:"Position",belt_level:"Blue",description:"The whizzer/collar tie is a technique used to control your opponent's arm and take them down to the ground.",youtube_url:"https://www.youtube.com/watch?v=pTbiUDyFDQE",tags:["whizzer","collar tie","BJJ","standing"],id:"whizzercollar-tie"},{name:"Grip Fighting",japanese_name:null,category:"Standing",type:"Position",belt_level:"Purple",description:"Grip fighting is a technique used to gain control of your opponent's arm and take them down to the ground.",youtube_url:"https://www.youtube.com/watch?v=CXX4A9Z4nEE",tags:["grip fighting","BJJ","standing"],id:"grip-fighting"},{name:"Ko Uchi Gari",japanese_name:"\u5c0f\u5185\u5208 (Minor Inner Reap)",category:"Standing",type:"Takedown",belt_level:"Purple",description:"A smaller, quicker reaping throw than O Uchi Gari. Reap opponent's supporting leg from the inside while pulling them diagonally forward. Often used as a setup for O Uchi Gari or other throws.",youtube_url:"https://www.youtube.com/watch?v=8WanR9-gk3U",tags:["judo","ko-uchi-gari","minor-reap","setup","combinations","ashi-waza"],id:"ko-uchi-gari"},{name:"Russian Tie",japanese_name:null,category:"Standing",type:"Position",belt_level:"Purple",description:"The Russian tie is a technique used to control your opponent's arm and take them down to the ground.",youtube_url:"https://www.youtube.com/watch?v=CXX4A9Z4nEE",tags:["Russian tie","BJJ","standing"],id:"russian-tie"},{name:"Underhook Battle",japanese_name:null,category:"Standing",type:"Position",belt_level:"Purple",description:"The underhook battle is a technique used to gain control of your opponent's arm and take them down to the ground.",youtube_url:"https://www.youtube.com/watch?v=CXX4A9Z4nEE",tags:["underhook battle","BJJ","standing"],id:"underhook-battle"},{name:"Advanced Foot Sweep",japanese_name:"De Ashi Barai",category:"Standing",type:"Throw",belt_level:"Yellow",description:"A timing-based foot sweep executed just as the opponent is about to place weight on their advancing foot. The foot is swept sideways across the mat.",youtube_url:"https://www.youtube.com/results?search_query=de+ashi+barai+judo",tags:["judo","ashi-waza","foot sweep","takedown"],id:"advanced-foot-sweep"},{name:"Circular Throw",japanese_name:"Tomoe Nage",category:"Standing",type:"Throw",belt_level:"Green",description:"A sacrifice throw where the attacker falls backward, placing a foot on the opponent's hip/stomach, and uses their momentum to propel the opponent over them.",youtube_url:"https://www.youtube.com/results?search_query=tomoe+nage+judo",tags:["judo","sutemi-waza","sacrifice throw","takedown"],id:"circular-throw"},{name:"Cornered Throw/Reversal",japanese_name:"Sumi Gaeshi",category:"Standing",type:"Throw",belt_level:"Green",description:"A sacrifice throw often used as a counter or from a clinch. The attacker drops under the opponent, hooks a leg inside the opponent's thigh, and flips them over sideways/backward.",youtube_url:"https://www.youtube.com/results?search_query=sumi+gaeshi+judo",tags:["judo","sutemi-waza","sacrifice throw","takedown"],id:"cornered-throwreversal"},{name:"Floating Hip Throw",japanese_name:"Uki Goshi",category:"Standing",type:"Throw",belt_level:"Yellow",description:"Similar to O Goshi but relies less on lifting and more on a twisting hip action. The attacker's hip is placed shallowly across the opponent's, and the throw is executed with a sudden twist.",youtube_url:"https://www.youtube.com/results?search_query=uki+goshi+judo",tags:["judo","koshi-waza","hip throw","takedown"],id:"floating-hip-throw"},{name:"Lifting Hip Throw",japanese_name:"Tsuri Goshi",category:"Standing",type:"Throw",belt_level:"Orange",description:"A hip throw that involves gripping the opponent's belt to lift them onto the hips before throwing. Effective against defensive opponents.",youtube_url:"https://www.youtube.com/results?search_query=tsuri+goshi+judo",tags:["judo","koshi-waza","hip throw","takedown"],id:"lifting-hip-throw"},{name:"One-arm Shoulder Throw",japanese_name:"Ippon Seoi Nage",category:"Standing",type:"Throw",belt_level:"Yellow",description:"A variation of the shoulder throw where the attacker clamps one of the opponent's arms (usually the lapel gripping arm) under their armpit/shoulder to load and throw.",youtube_url:"https://www.youtube.com/results?search_query=ippon+seoi+nage+judo",tags:["judo","te-waza","shoulder throw","takedown"],id:"onearm-shoulder-throw"},{name:"Shoulder Throw",japanese_name:"Seoi Nage",category:"Standing",type:"Throw",belt_level:"Yellow",description:"A classic shoulder throw where the attacker loads the opponent onto their back and throws them over the shoulder. Can be performed standing or dropping (drop seoi nage).",youtube_url:"https://www.youtube.com/results?search_query=seoi+nage+judo",tags:["judo","te-waza","shoulder throw","takedown"],id:"shoulder-throw"},{name:"Sweeping Hip Throw",japanese_name:"Harai Goshi",category:"Standing",type:"Throw",belt_level:"Orange",description:"A powerful throw where the attacker breaks the opponent's balance forward, turns in, and sweeps the opponent's leg with the outside of their own thigh/leg while lifting with the hips.",youtube_url:"https://www.youtube.com/results?search_query=harai+goshi+judo",tags:["judo","koshi-waza","hip throw","takedown"],id:"sweeping-hip-throw"},{name:"Sweeping Lifting Pulling Foot",japanese_name:"Harai Tsurikomi Ashi",category:"Standing",type:"Throw",belt_level:"Orange",description:"An advanced foot technique where the opponent is drawn forward and lifted, and the attacker sweeps the opponent's leg backward while retreating.",youtube_url:"https://www.youtube.com/results?search_query=harai+tsurikomi+ashi+judo",tags:["judo","ashi-waza","leg throw","takedown"],id:"sweeping-lifting-pulling-foot"},{name:"Two-arm Shoulder Throw",japanese_name:"Morote Seoi Nage",category:"Standing",type:"Throw",belt_level:"Orange",description:"A shoulder throw executed with both hands gripping the gi (usually sleeve and lapel). The lifting action comes from the forearm driving up under the opponent's armpit.",youtube_url:"https://www.youtube.com/results?search_query=morote+seoi+nage+judo",tags:["judo","te-waza","shoulder throw","takedown"],id:"twoarm-shoulder-throw"},{name:"Back Take from Turtle",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"White",description:"A technique to take the opponent's back from the turtle position. The practitioner controls the opponent's hips and shoulders, using a seatbelt grip to secure the back take.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Back+Take+from+Turtle",tags:["turtle","back control","fundamental","submission setup"],id:"back-take-from-turtle"},{name:"Guard to Turtle (Defensive)",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"White",description:"A defensive transition where the practitioner moves from the guard position to the turtle position to avoid passes and reset their position. This is often used when the guard is in danger of being passed.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Guard+to+Turtle+defensive+transition",tags:["guard","turtle","defensive","positioning"],id:"guard-to-turtle-defensive"},{name:"Half Guard to Full Guard",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"White",description:"This transition involves recovering from half guard to full guard by freeing the trapped leg and re-establishing a closed guard. It requires hip movement and control of the opponent's posture.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Half+Guard+to+Full+Guard+transition",tags:["half guard","full guard","recovery","positioning"],id:"half-guard-to-full-guard"},{name:"Mount to Back Control",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"White",description:"This transition involves moving from the mount position to the opponent's back, allowing for the application of chokes and control. The practitioner typically traps one of the opponent's arms and uses a hip escape to slide into back control.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Mount+to+Back+Control+transition",tags:["mount","back control","fundamental","submission setup"],id:"mount-to-back-control"},{name:"Side Control to Mount",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"White",description:"A fundamental transition in Brazilian Jiu-Jitsu where the practitioner moves from side control to the mount position. This technique involves controlling the opponent's hips and shoulders to slide the knee across their body, securing the mount.",youtube_url:"https://www.youtube.com/watch?v=YaVW3985p1I",tags:["side control","mount","fundamental","top game"],id:"side-control-to-mount"},{name:"Turtle to Guard (Recovery)",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"White",description:"A recovery technique where the practitioner moves from the turtle position back to the guard. This involves using hip movement and leg placement to re-establish a guard position and prevent the opponent from advancing.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Turtle+to+Guard+recovery",tags:["turtle","guard recovery","fundamental","positioning"],id:"turtle-to-guard-recovery"},{name:"Back Take from Half Guard",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"Purple",description:"An advanced technique to take the opponent's back from half guard. The practitioner uses underhooks and hip movement to slide into back control, often requiring precise timing and control.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Back+Take+from+Half+Guard",tags:["half guard","back control","advanced","submission setup"],id:"back-take-from-half-guard"},{name:"Butterfly Guard to X-Guard",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"Purple",description:"This transition involves moving from butterfly guard to X-guard, a position that allows for powerful sweeps and leg entanglements. The practitioner uses their hooks and grips to elevate and control the opponent's leg.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Butterfly+Guard+to+X-Guard+transition",tags:["butterfly guard","x-guard","sweeps","leg entanglements"],id:"butterfly-guard-to-xguard"},{name:"Half Guard to Deep Half",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"Purple",description:"An advanced transition where the practitioner moves from half guard to deep half guard, a position that offers significant control and sweeping opportunities. This requires precise hip movement and underhooking the opponent's leg.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+Half+Guard+to+Deep+Half+transition",tags:["half guard","deep half","advanced","sweeps"],id:"half-guard-to-deep-half"},{name:"X-Guard to Leg Entanglements",japanese_name:null,category:"Transitions",type:"Transition",belt_level:"Brown",description:"An advanced transition where the practitioner moves from X-guard to more complex leg entanglements like 50/50, inside sankaku, or outside ashi garami. This requires precise control of the opponent's legs and hips.",youtube_url:"https://www.youtube.com/results?search_query=BJJ+X-Guard+to+Leg+Entanglements+transition",tags:["x-guard","leg entanglements","advanced","submission setup"],id:"xguard-to-leg-entanglements"},{name:"Back Take from Turtle",japanese_name:null,category:"Turtle",type:"Positional",belt_level:"White",description:"A fundamental transition from top turtle to back control. The attacker secures a seatbelt grip (one arm over the shoulder, one under the armpit) and uses hooks (legs) to secure the opponent's hips. The attacker may break the opponent down to a hip or roll them to expose the back, establishing the four points of back mount.",youtube_url:"https://www.youtube.com/watch?v=YUoHqTBoo9c",tags:["Transition","Back Take","Top Game","Position"],id:"back-take-from-turtle"},{name:"Cross Collar Choke from Turtle",japanese_name:"Okuri Eri Jime",category:"Turtle",type:"Submission",belt_level:"White",description:"Also known as the Sliding Collar Choke. From the back or side turtle position, the attacker feeds one hand deep into the opponent's collar across the neck. The second hand grabs the opposite lapel or controls the leg/arm. The attacker then applies pressure by expanding their chest and pulling the collars, or by rolling (bow and arrow style) to finish the choke.",youtube_url:"https://www.youtube.com/watch?v=1hw7pCq7CfE",tags:["Choke","Gi","Top Game","Back Attack"],id:"cross-collar-choke-from-turtle"},{name:"Sit-Out Escape",japanese_name:null,category:"Turtle",type:"Escape",belt_level:"White",description:"A basic escape from the turtle position, particularly against a front headlock or sprawl. The defender posts one arm and 'sits out' by shooting their legs through to the opposite side, ending up in a seated position facing the opponent or maneuvering to take the opponent's back.",youtube_url:"https://www.youtube.com/watch?v=o55M0DMesfE",tags:["Escape","Wrestling","Bottom Game","Defense"],id:"sitout-escape"},{name:"Technical Stand-Up from Turtle",japanese_name:null,category:"Turtle",type:"Escape",belt_level:"White",description:"A safe method to return to standing from the turtle position. The defender posts an arm and the opposite foot, lifts their hips, and threads the free leg back to a standing base, often while maintaining a frame or distance to prevent the opponent from taking the back or tackling.",youtube_url:"https://www.youtube.com/watch?v=Hto8vSvnry0",tags:["Escape","Stand Up","Defense","Bottom Game"],id:"technical-standup-from-turtle"},{name:"Turtle Guard Recovery",japanese_name:null,category:"Turtle",type:"Escape",belt_level:"White",description:"The process of transitioning from the bottom turtle position back to a guard (closed, open, or half). Common methods include framing to create space and 'shrimping' the hips back, or performing a shoulder roll (Granby) to re-insert the legs between the defender and the attacker.",youtube_url:"https://www.youtube.com/watch?v=RRp5tficE00",tags:["Escape","Guard Recovery","Bottom Game","Defense"],id:"turtle-guard-recovery"},{name:"Anaconda Choke",japanese_name:null,category:"Turtle",type:"Submission",belt_level:"Blue",description:"A head and arm choke typically applied from the front headlock position (top turtle). The attacker threads their arm under the opponent's neck and through the armpit on the same side, locking their hands (gable grip or figure-four). They then roll the opponent (gator roll) onto their side/back to tighten the compression, often trapping the opponent's leg with their own legs.",youtube_url:"https://www.youtube.com/watch?v=mHgW7pXBtpI",tags:["Choke","No-Gi","Top Game","Front Headlock"],id:"anaconda-choke"},{name:"Clock Choke",japanese_name:"Koshi Jime (variation)",category:"Turtle",type:"Submission",belt_level:"Blue",description:"A powerful choke from the top turtle position. The attacker grips the opponent's far collar with one hand (often across the neck) and posts the other hand or controls the near wrist. The attacker then walks their legs around towards the opponent's head (like the hands of a clock) while applying downward pressure with their chest and hips, tightening the collar grip against the neck.",youtube_url:"https://www.youtube.com/watch?v=ihQnprnIHBs",tags:["Choke","Gi","Top Game","Submission"],id:"clock-choke"},{name:"Crucifix",japanese_name:"Jigoku Jime (Hell Strangle)",category:"Turtle",type:"Submission",belt_level:"Blue",description:"A dominant position and submission setup where the attacker isolates one of the opponent's arms with their legs and the other with their arms, forming a cross shape. From this position, the attacker can apply various chokes (like the collar choke or one-armed rear naked choke) or neck cranks.",youtube_url:"https://www.youtube.com/watch?v=bf6uxUzo0Wc",tags:["Submission","Position","Top Game","Choke"],id:"crucifix"},{name:"D'Arce Choke",japanese_name:"Brabo Choke",category:"Turtle",type:"Submission",belt_level:"Blue",description:"A head and arm choke similar to the Anaconda but with a different entry. The attacker shoots their arm under the opponent's near armpit and across the neck, locking their hands on the far side of the neck (often securing a figure-four grip on their own bicep). Pressure is applied by dropping the weight and squeezing, often while sprawling or hooking the opponent's leg.",youtube_url:"https://www.youtube.com/watch?v=VOliFfkp5Ik",tags:["Choke","No-Gi","Top Game","Front Headlock"],id:"darce-choke"},{name:"Peruvian Necktie",japanese_name:null,category:"Turtle",type:"Submission",belt_level:"Blue",description:"A choke from the front headlock position. The attacker secures a guillotine-like grip on the head and arm, then steps their legs over the opponent's back and head, sitting back to use their legs as a fulcrum to drive the opponent's head down into the choke.",youtube_url:"https://www.youtube.com/watch?v=ZG4nalSL6kw",tags:["Choke","No-Gi","Top Game","Front Headlock"],id:"peruvian-necktie"},{name:"Rolling Back Take",japanese_name:null,category:"Turtle",type:"Positional",belt_level:"Blue",description:"An advanced entry to the back from top turtle. The attacker rolls over their own shoulder (often holding the opponent's waist or legs) to pull the opponent into a back control position or 'The Truck'. This momentum-based movement can surprise opponents who are defending static back takes.",youtube_url:"https://www.youtube.com/watch?v=sER-a0OxVuI",tags:["Transition","Back Take","Top Game","Rolling"],id:"rolling-back-take"},{name:"Turtle Roll (Granby Roll)",japanese_name:null,category:"Turtle",type:"Escape",belt_level:"Blue",description:"An escape used when the opponent is attacking from the side or back. The bottom player tucks their head and shoulder (near the opponent's pressure) and rolls across their upper back/shoulders. This rolling motion creates space, allowing the defender to recover guard or scramble to a neutral position.",youtube_url:"https://www.youtube.com/watch?v=BKeIzgngC18",tags:["Escape","Movement","Defense","Bottom Game"],id:"turtle-roll-granby-roll"}]},731,[]);
