__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"glossaryTerms",{enumerable:!0,get:function(){return o}});const o=[{id:'pos-001',term:'Guard',definition:'A position where you are on your back with your opponent on top or in front of you.',example:'A closed guard is when your legs are wrapped around your opponent\'s torso.',category:'Positions',difficulty:'beginner'},{id:'pos-002',term:'Mount',definition:'A dominant position where you are sitting on top of your opponent\'s torso.',example:'From mount, you can control your opponent and transition to other positions.',category:'Positions',difficulty:'beginner'},{id:'pos-003',term:'Side Control',definition:'A dominant position where you are controlling your opponent from the side.',example:'Maintaining side control allows you to apply pressure and set up submissions.',category:'Positions',difficulty:'beginner'},{id:'pos-004',term:'Back Mount',definition:'A dominant position where you are on top of your opponent with your back to their chest.',example:'Back mount gives you access to rear naked chokes and other back submissions.',category:'Positions',difficulty:'intermediate'},{id:'pos-005',term:'Turtle',definition:'A defensive position where you are on your back with your legs wrapped around your opponent.',example:'You can escape from turtle by using your legs to sweep your opponent.',category:'Positions',difficulty:'beginner'},{id:'pos-006',term:'Half Guard',definition:'A position where you are on your back with one leg wrapped around your opponent.',example:'From half guard, you can transition to closed guard or sweep your opponent.',category:'Positions',difficulty:'beginner'},{id:'pos-007',term:'North-South',definition:'A dominant position where you are sitting in front of your opponent with your arms around their neck.',example:'North-south allows you to apply rear naked chokes and maintain control.',category:'Positions',difficulty:'intermediate'},{id:'pos-008',term:'Kesa Gatame',definition:'A submission hold involving wrapping your arm around and behind your opponent\'s head or neck.',example:'Kesa gatame can be used as a setup to other submissions or as a submission itself.',category:'Positions',difficulty:'intermediate'},{id:'pos-009',term:'Reverse Kesa',definition:'A submission hold similar to Kesa Gatame but from a reverse position.',example:'This hold is used in transitions and as a submission from different positions.',category:'Positions',difficulty:'intermediate'},{id:'pos-010',term:'Spider Guard',definition:'A defensive and attacking position where you place your hands on the ground and your legs wrapped around your opponent.',example:'Spider guard allows you to control your opponent while setting up sweeps.',category:'Positions',difficulty:'intermediate'},{id:'pos-011',term:'Lasso Guard',definition:'A type of guard where your opponent\'s head is positioned between your legs.',example:'This position allows you to control your opponent\'s movement from the head and neck.',category:'Positions',difficulty:'intermediate'},{id:'pos-012',term:'De La Riva',definition:'A guard position where one leg is wrapped around your opponent\'s head.',example:'The De La Riva guard is used to control your opponent while preparing for sweeps or submissions.',category:'Positions',difficulty:'intermediate'},{id:'pos-013',term:'X-Guard',definition:'A type of guard that allows you to control your opponent with your legs wrapped in an X shape.',example:'X-guard gives you the ability to sweep and submit from a strong defensive position.',category:'Positions',difficulty:'intermediate'},{id:'pos-014',term:'Butterfly Guard',definition:'A guard position where your legs are in a butterfly shape, both knees bent and touching.',example:'This guard is used for controlling and sweeping as a beginner.',category:'Positions',difficulty:'beginner'},{id:'pos-015',term:'Rubber Guard',definition:'A guard position where your legs are wrapped around your opponent with a rubber-like flexibility.',example:'The rubber guard is a flexible and adaptive guard used in various situations.',category:'Positions',difficulty:'intermediate'},{id:'sub-001',term:'Triangle Choke',definition:'A submission hold using your legs to choke your opponent by placing them in between your legs.',example:'The triangle choke is effective from side control and mount.',category:'Submissions',difficulty:'beginner'},{id:'sub-002',term:'Armbar',definition:'A submission hold where you use your legs to apply pressure and hyperextend your opponent\'s arm.',example:'You can set up an armbar from closed guard or when controlling your opponent.',category:'Submissions',difficulty:'beginner'},{id:'sub-003',term:'Kimura',definition:'A submission hold that applies pressure to the opponent\'s shoulder or arm.',example:'The Kimura is often set up by trapping your opponent in your guard.',category:'Submissions',difficulty:'beginner'},{id:'sub-004',term:'Americana',definition:'A submission that hyperextends your opponent\'s arm using your leg and body positioning.',example:'You can apply the americana from mount or from other dominant positions.',category:'Submissions',difficulty:'intermediate'},{id:'sub-005',term:'Rear Naked Choke',definition:'A submission hold where you wrap your legs around your opponent\'s neck from behind.',example:'Rear naked choke is one of the most common finishes in BJJ.',category:'Submissions',difficulty:'beginner'},{id:'sub-006',term:'Guillotine',definition:'A submission hold using your arms to choke your opponent by wrapping them around their neck.',example:'This technique is often used from guard or when you are on top.',category:'Submissions',difficulty:'beginner'},{id:'sub-007',term:'Omoplata',definition:'A submission that hyperextends your opponent\'s shoulder and arm.',example:'The omoplata is a more advanced submission held from back control.',category:'Submissions',difficulty:'intermediate'},{id:'sub-008',term:'D\'Arce Choke',definition:'A choking submission that uses your arms to apply pressure at the opponent\'s neck and shoulders.',example:'D\'Arce choke is effective from various positions including mount and side control.',category:'Submissions',difficulty:'intermediate'},{id:'sub-009',term:'Anaconda Choke',definition:'A choking hold where you encircle your opponent\'s head with your arms.',example:'Anaconda choke is set up from the back and can be applied from different dominant positions.',category:'Submissions',difficulty:'intermediate'},{id:'sub-010',term:'Heel Hook',definition:'A submission that uses your opponent\'s heel to apply pressure on their hip or leg.',example:'This technique is often used from guard positions.',category:'Submissions',difficulty:'intermediate'},{id:'sub-011',term:'Kneebar',definition:'A submission that hyperextends your opponent\'s knee using your leg.',example:'Kneebar is commonly used from guard positions when you have access to the opponent\'s knee.',category:'Submissions',difficulty:'intermediate'},{id:'sub-012',term:'Toe Hold',definition:'A submission that uses the toe to press against the opponent\'s body to apply pressure.',example:'Toe holds can be used in different positions for controlling and submitting.',category:'Submissions',difficulty:'intermediate'},{id:'sub-013',term:'Wristlock',definition:'A submission that hyperextends the opponent\'s wrist.',example:'This technique is often used as a transition or to control an opponent\'s hand.',category:'Submissions',difficulty:'intermediate'},{id:'sub-014',term:'Ezekiel Choke',definition:'A choking submission that applies pressure around the opponent\'s throat using your arms.',example:'This is a more advanced choke used from specific positions.',category:'Submissions',difficulty:'intermediate'},{id:'sub-015',term:'Loop Choke',definition:'A choking submission held by placing your leg around your opponent\'s neck.',example:'Loop chokes are effective from positions where you have good access to the opponent\'s neck.',category:'Submissions',difficulty:'intermediate'},{id:'sweep-001',term:'Scissors Sweep',definition:'A sweeping technique using your legs to sweep your opponent, similar to a scissors motion.',example:'Scissors sweep is used from guard to escape to a more dominant position.',category:'Sweeps',difficulty:'beginner'},{id:'sweep-002',term:'Hip Bump Sweep',definition:'A sweep that uses your hip to push your opponent over.',example:'Hip bump sweep works from guard or side control to transition to mount.',category:'Sweeps',difficulty:'beginner'},{id:'sweep-003',term:'Flower Sweep',definition:'A sweeping technique that uses your leg movement to pull your opponent over.',example:'This sweep is often applied from the butterfly guard position.',category:'Sweeps',difficulty:'intermediate'},{id:'sweep-004',term:'Elevator Sweep',definition:'A sweeping technique used to move your opponent from one position to another.',example:'The elevator sweep can be applied from different positions like guard.',category:'Sweeps',difficulty:'intermediate'},{id:'sweep-005',term:'Pendulum Sweep',definition:'A sweep technique that uses a pendulum motion to destabilize your opponent.',example:'This technique is often used from guard positions to escape to mount.',category:'Sweeps',difficulty:'intermediate'},{id:'sweep-006',term:'Butterfly Sweep',definition:'A sweep applied from butterfly guard using your legs.',example:'Butterfly sweep is effective against opponents who are trying to mount you.',category:'Sweeps',difficulty:'intermediate'},{id:'sweep-007',term:'X-Guard Sweep',definition:'A sweep technique using the X-guard position to sweep your opponent.',example:'X-guard sweep can be used to escape to mount from a back position.',category:'Sweeps',difficulty:'intermediate'},{id:'sweep-008',term:'De La Riva Sweep',definition:'A sweep applied from the De La Riva guard position.',example:'This sweep is a common way to escape from the De La Riva position.',category:'Sweeps',difficulty:'intermediate'},{id:'guard-001',term:'Closed Guard',definition:'A defensive position where your legs are wrapped around your opponent\'s torso.',example:'Closed guard is fundamental for escaping and setting up sweeps.',category:'Guards',difficulty:'beginner'},{id:'guard-002',term:'Open Guard',definition:'A guard position where your legs are open and not wrapped around your opponent.',example:'From open guard, you can sweep and control your opponent.',category:'Guards',difficulty:'beginner'},{id:'guard-003',term:'Half Guard',definition:'A position where you are on your back with one leg wrapped around your opponent.',example:'Half guard is a good neutral position for escaping control.',category:'Guards',difficulty:'beginner'},{id:'guard-004',term:'Butterfly',definition:'A type of guard with knees bent and feet wide in a butterfly position.',example:'Butterfly guard is commonly used for controlling and escaping.',category:'Guards',difficulty:'beginner'},{id:'guard-005',term:'Spider',definition:'A guard position where your hands are on the ground and legs wrapped around your opponent.',example:'Spider guard allows strong control while setting up sweeps.',category:'Guards',difficulty:'intermediate'},{id:'guard-006',term:'De La Riva',definition:'A guard where one leg is wrapped around your opponent\'s head.',example:'De La Riva guard is used for controlling and sweeping.',category:'Guards',difficulty:'intermediate'},{id:'guard-007',term:'X-Guard',definition:'A guard using an X-shape with your legs around your opponent.',example:'X-guard is effective for transitioning and sweeping.',category:'Guards',difficulty:'intermediate'},{id:'guard-008',term:'Rubber Guard',definition:'A flexible guard with legs wrapped around your opponent.',example:'Rubber guard provides flexibility in controlling opponents.',category:'Guards',difficulty:'intermediate'},{id:'guard-009',term:'Lasso',definition:'A guard where your opponent\'s head is positioned between your legs.',example:'Lasso guard is used for controlling and preparing sweeps.',category:'Guards',difficulty:'intermediate'},{id:'guard-010',term:'K-Guard',definition:'A position where both legs are positioned with your knees close to your opponent.',example:'K-guard is used for controlling and escaping.',category:'Guards',difficulty:'intermediate'},{id:'guard-011',term:'Worm Guard',definition:'A position where your lower body is positioned in a worm or fetal position.',example:'Worm guard is defensive and allows for sweeps.',category:'Guards',difficulty:'intermediate'},{id:'conc-001',term:'Base',definition:'Your stable and balanced position that allows you to control your opponent.',example:'A good base allows you to maintain control and execute techniques effectively.',category:'Concepts',difficulty:'beginner'},{id:'conc-002',term:'Posture',definition:'Your body position and balance while in BJJ.',example:'Good posture helps in maintaining control and executing moves without losing balance.',category:'Concepts',difficulty:'beginner'},{id:'conc-003',term:'Framing',definition:'The technique of positioning your arms to control your opponent\'s movement.',example:'Framing is used to control your opponent and prevent them from escaping.',category:'Concepts',difficulty:'intermediate'},{id:'conc-004',term:'Bridging',definition:'The technique of lifting your hips and arching your back to counter a sweep or submission.',example:'Bridging is used to prevent your opponent from sweeping or submitting.',category:'Concepts',difficulty:'beginner'},{id:'conc-005',term:'Shrimping',definition:'The technique of moving your hips to escape or break free from opponent\'s control.',example:'Shrimping is effective when trying to avoid a submission from guard.',category:'Concepts',difficulty:'beginner'},{id:'conc-006',term:'Hip Escape',definition:'The technique of using your hips to escape from an opponent\'s control.',example:'Hip escape is used when your opponent tries to control your hips.',category:'Concepts',difficulty:'beginner'},{id:'conc-007',term:'Technical Stand-Up',definition:'The technique of standing up from the ground using technical movements.',example:'Technical stand-up helps you escape from guard and regain your feet.',category:'Concepts',difficulty:'beginner'},{id:'conc-008',term:'Grips',definition:'The way you hold or grab your opponent in BJJ.',example:'Effective grips help you control your opponent and apply submissions.',category:'Concepts',difficulty:'beginner'},{id:'conc-009',term:'Weight Distribution',definition:'How you distribute your body weight in BJJ positions.',example:'Proper weight distribution gives you better balance and control.',category:'Concepts',difficulty:'intermediate'},{id:'conc-010',term:'Pressure',definition:'The force you apply to control your opponent.',example:'Applying pressure is key to maintaining dominant positions.',category:'Concepts',difficulty:'intermediate'},{id:'conc-011',term:'Space Creation',definition:'The technique of creating distance and positioning to control the fight.',example:'Creating space allows you to control the fight by setting up your own movements.',category:'Concepts',difficulty:'intermediate'},{id:'port-001',term:'Jiu-Jitsu',definition:'The Japanese term for "gentle art" - a martial art focused on grappling.',example:'BJJ is known as the gentle art because it relies on technique rather than strength.',category:'Portuguese',difficulty:'beginner'},{id:'port-002',term:'Kimura',definition:'A submission technique named after the Japanese martial artist Masashi Kimura.',example:'The kimura submission is named after its creator.',category:'Portuguese',difficulty:'intermediate'},{id:'port-003',term:'Americana',definition:'A submission move named after the American wrestling style of the same name.',example:'This submission was developed with references to American wrestling techniques.',category:'Portuguese',difficulty:'intermediate'},{id:'port-004',term:'Mata Le\xe3o',definition:'A Portuguese term for "lion\'s eye", often used in guard positions.',example:'A mata le\xe3o guard provides good control from the top position.',category:'Portuguese',difficulty:'intermediate'},{id:'port-005',term:'Berimbolo',definition:'A Portuguese term that means "tumble" or "to roll", used to describe a rolling motion.',example:'Berimbolo is used when describing rolling motions in defensive positions.',category:'Portuguese',difficulty:'intermediate'},{id:'port-006',term:'Jogo Bonito',definition:'A Portuguese term meaning "beautiful game", referring to proper BJJ technique.',example:'Jogo bonito emphasizes technique and control over brute force.',category:'Portuguese',difficulty:'intermediate'},{id:'port-007',term:'Oss',definition:'A Portuguese term meaning "soul" or "spirit", often used in the context of BJJ culture.',example:'Oss is a term used to describe the spirit that BJJ practitioners carry with them.',category:'Portuguese',difficulty:'intermediate'},{id:'port-008',term:'Saudade',definition:'A Portuguese emotion meaning "longing" or "nostalgia", often used to describe the longing for rolling.',example:'Saudade is used to describe the feeling of missing the training and rolling with others.',category:'Portuguese',difficulty:'intermediate'}]},764,[]);
